fn factorial(n: i32) -> Result<u128, String> {
    if n < 0 {
        return Err("El número debe ser mayor o igual a cero.".to_string());
    }

    match n {
        0 => Ok(1),
        _ => factorial(n - 1).map(|res| res * n as u128),
    }
}

fn main() {
    let test_cases = [5, 0, -3];

    for &num in &test_cases {
        match factorial(num) {
            Ok(result) => println!("El factorial de {} es {}", num, result),
            Err(e) => println!("Error al calcular el factorial de {}: {}", num, e),
        }
    }
}
