/**
 * Realiza una solicitud GET con reintentos automáticos.
 * @param {string} url - La URL de la API.
 * @param {number} maxRetries - Número máximo de intentos (por defecto 3).
 * @returns {Promise<any>} - Los datos parseados en JSON.
 */
const fetchDataWithRetry = async (url, maxRetries = 3) => {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      const isLastAttempt = attempt === maxRetries;

      if (isLastAttempt) {
        console.error(`Error final tras ${maxRetries} intentos:`, error.message);
        throw new Error(`No se pudo obtener los datos después de ${maxRetries} intentos.`);
      }

      const delay = attempt * 1000; // Backoff exponencial simple (opcional)
      console.warn(`Intento ${attempt} fallido. Reintentando en ${delay}ms...`);
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
};

// Ejemplo de uso:
const API_URL = 'https://jsonplaceholder.typicode.com/posts/1';

fetchDataWithRetry(API_URL)
  .then((data) => console.log('Datos recibidos:', data))
  .catch((err) => console.error('Error en la aplicación:', err));
